content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一個袋子嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 gei3 wo3 yi1 ge4 dai4zi0 ma0?",
      "translation_en": "Excuse me, could you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나를 주시겠어요?"
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Excuse me, could you add boba for me?",
      "translation_ko": "죄송합니다, 타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "店員，可以給我菜單看一下嗎？",
      "pinyin": "Diànyuán, kěyǐ gěi wǒ càidān kàn yīxià ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 gei3 wo3 cai4dan1 kan4 yi1xia4 ma0?",
      "translation_en": "Staff, could you let me take a look at the menu?",
      "translation_ko": "점원님, 메뉴판을 좀 볼 수 있을까요?"
    },
    {
      "text": "我想要一杯中杯紅茶，半糖少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi hóngchá, bàn táng shǎo bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 hong2cha2, ban4 tang2 shao3 bing1, ke3yi3 ma0?",
      "translation_en": "I would like a medium black tea, half sugar and less ice, okay?",
      "translation_ko": "중간 크기 홍차 한 잔, 반당 적게 얼음으로 해 주시겠어요?"
    },
    {
      "text": "可以給我兩根吸管嗎？謝謝。",
      "pinyin": "Kěyǐ gěi wǒ liǎng gēn xīguǎn ma? Xièxie.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 liang3 gen1 xi1guan3 ma0? xie4xie0.",
      "translation_en": "Could you give me two straws? Thank you.",
      "translation_ko": "빨대 두 개를 주시겠어요? 감사합니다."
    },
    {
      "text": "不好意思，可以再說一次嗎？我聽不太清楚。",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì ma? Wǒ tīng bù tài qīngchu.",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 zai4 shuo1 yi1 ci4 ma0? wo3 ting1 bu4 tai4 qing1chu0.",
      "translation_en": "Excuse me, could you say that again? I didn't hear clearly.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요? 잘 안 들려요."
    },
    {
      "text": "我想要一杯大杯綠茶，去冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi lǜchá, qù bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 lü4cha2, qu4 bing1, ke3yi3 ma0?",
      "translation_en": "I would like a large green tea, no ice, okay?",
      "translation_ko": "큰 녹차 한 잔, 얼음 없이 해 주시겠어요?"
    },
    {
      "text": "麻煩你，可以幫我外帶嗎？",
      "pinyin": "Máfan nǐ, kěyǐ bāng wǒ wàidài ma?",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 bang1 wo3 wai4dai4 ma0?",
      "translation_en": "Excuse me, could you make it for takeout?",
      "translation_ko": "실례합니다, 포장해 주시겠어요?"
    },
    {
      "text": "客人，可以等一下嗎？馬上就好。",
      "pinyin": "Kèrén, kěyǐ děng yīxià ma? Mǎshàng jiù hǎo.",
      "pinyin_numeric": "ke4ren2, ke3yi3 deng3 yi1xia4 ma0? ma3shang4 jiu4 hao3.",
      "translation_en": "Customer, could you wait a moment? It will be ready soon.",
      "translation_ko": "손님, 잠시만 기다려 주시겠어요? 곧 준비됩니다."
    }
  ]
}
